func lengthOfLongestSubstring(s string) int {
	if len(s) == 0 {
		return 0
	}
	if len(s) == 1 {
		return 1
	}
	/*if len(s) >= 31000 {
		return _lengthOfLongestSubstring(s)
	}*/
	mu := sync.Mutex{}
	wg := sync.WaitGroup{}
	_max := 0
	for i := range len(s) - 1 {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			c := _lengthOfLongestSubstring(s[i:])
			mu.Lock()
			if c > _max {
				_max = c
			}
			mu.Unlock()
		}(i)
	}
	wg.Wait()
	return _max
}

func _lengthOfLongestSubstring(s string) int {
	_max := 0
	count := 0
	b := []byte(s)
	m := make(map[byte]bool, 200)
	i := 0
	for {
		if i == len(b) {
			break
		}
		if m[b[i]] == false {
			count++
			m[b[i]] = true
			i++
		} else {
			if count > _max {
				_max = count
			}
			count = 0
			clear(m)
			if b[i] != b[i-1] {
				i--
			}
		}
	}
	if count > _max {
		return count
	}
	return _max
}

func lengthOfLongestSubstring2(s string) int {
	if len(s) == 1 {
		return 1
	}
	count := 0
	buffer := []byte(s)
	n := len(buffer)
	m := make(map[byte]bool, n)
	for i := range n - 1 {
		for j := range i + 1 {
			clear(m)
			count = 0
			for _, b := range buffer[j : n-i+j] {
				if m[b] == false {
					m[b] = true
					count++
				} else {
					break
				}
			}
			if count == n-i {
				//fmt.Println(i, j, n-i, string(buffer[j:n-i+j]))
				return count
			}
		}
	}
	return count
}

